---@class StructDreamTripInfo
local StructDreamTripInfo = LxClass("StructDreamTripInfo", nil)
function StructDreamTripInfo:StructDreamTripInfo()
	---@type number 本轮开启的地图Id
	self.mapId = 0

	---@type number 当前地图等级 RefId
	self.mapLvl = 0

	---@type number 当前地图等级
	self.mapLevel = 0

	---@type number 上一次玩的地图等级 RefId
	self.lastMapLvlRefId = 0

	---@type number 上一次玩的地图等级
	self.lastMapLvl = 0

	---@type number 地图刷新时间
	self.refreshTime = 0

	---@type number 当前所在平台索引
	self.index = 0

	---@type table<string> 已完成平台事件Id
	self.successIndex = {}
	---@type table<string,StructDreamTripEventInfo> 已完成平台事件Id
	self.successIndexKey = {}

	---@type table<StructDreamTripGrid> 地图事件信息
	self.gridInfos = {}

	---@type number  true代表已结算
	self.balance = false

	---@type number 地图路线Id
	self.mapGameId = 0

	---@type number 岔路事件剩余步数,0标识未处于岔路停止状态
	self.byroadIndex = 0

	---@type number 剩余骰子数（如果大于0，则需要走完才能继续摇骰子）
	self.diceCount = 0

	---@type number 飞行标记 1=飞行中
	self.flight = 0

	---@type boolean 是否飞行中
	self.isFlight = false
end

function StructDreamTripInfo:CreateByPb(pb)
	self.mapId = pb.mapId

	self.mapLvl = pb.mapLvl
	--- 当前地图等级
	self.mapLevel = gModelFastDreamTrip:GetDreamTripMapLevelByRefId(self.mapLvl)

	self.lastMapLvlRefId = pb.lastMapLvl
	self.lastMapLvl = 0
	if self.lastMapLvlRefId > 0 then
		self.lastMapLvl = gModelFastDreamTrip:GetDreamTripMapLevelByRefId(self.lastMapLvlRefId)
	end

	self.refreshTime = tonumber(pb.refreshTime)

	self.index = pb.index

	local recordSucEIdMap = {}
	self.successIndex = {}
	self.successIndexKey = {}
	local successIndex = pb.successIndex
	for i,v in ipairs(successIndex) do
		table.insert(self.successIndex,v)
		recordSucEIdMap[v] = v
	end


	self.gridInfos = {}
	local gridData = {}
	local gridInfo = pb.gridInfo
	for i,v in ipairs(gridInfo) do
		---@type StructDreamTripEventInfo
		local serverData = self:CreateDreamTripEventInfo(v)
		local index = serverData.index
		local state = serverData.state
		if state ~= StructDreamTripGrid.FINISH then
			local moreInfo = serverData.moreInfo
			--- 盗宝者战斗位置
			local battleList = moreInfo[StructDreamTripEventInfo.ROBBER_BATTLE]
			if battleList and #battleList > 0 then
				index = battleList[#battleList].battleIdx or index
			end
		end
		local indexList = gridData[index]
		if not indexList then
			indexList = {}
			gridData[index] = indexList
		end
		table.insert(indexList,serverData)


		if recordSucEIdMap[serverData.eventId] then
			self.successIndexKey[serverData.eventId] = serverData
		end
	end

	--- 初始的台阶
	local defaultIndex = 0
	local defaultGrid = StructDreamTripGrid:New()
	defaultGrid:SaveData({index = defaultIndex,indexList = {}})
	self.gridInfos[defaultIndex] = defaultGrid

	for index,indexList in pairs(gridData) do
		local grid = StructDreamTripGrid:New()
		grid:SaveData({index = index,indexList = indexList})
		self.gridInfos[index] = grid
	end

	local themeCfg = gModelFastDreamTrip:GetMapRefByMapId(self.mapId)
	if themeCfg then
		local endPlatform = themeCfg.endPlatform
		---@type StructDreamTripGrid
		local endGrids = self.gridInfos[endPlatform]
		if not endGrids then
			local endEventRefId = themeCfg.endEvent
			local eventInfo = self:CreateDreamTripEventInfo({
				eventId = "-1",
				index = endPlatform,
				eventRefId = endEventRefId,
				eventType = gModelFastDreamTrip:GetDreamTripEventTypeByRefId(endEventRefId),
				moreInfo = "",
				reward = {},
				state = self.index == endPlatform and 2 or 1
			})
			local endGrid = StructDreamTripGrid:New()
			endGrid:SaveData({
				index = endPlatform,
				indexList = {eventInfo}
			})
			self.gridInfos[endPlatform] = endGrid
		end
	end

	local balance = pb.balance
	self.balance = balance and balance == 1 or false

	self.mapGameId = pb.mapGameId

	self.byroadIndex = pb.byroadIndex

	self.diceCount = pb.diceCount

	local flight = pb.flight
	self.flight = flight

	self.isFlight = flight == 1
end

---@return StructDreamTripEventInfo
function StructDreamTripInfo:CreateDreamTripEventInfo(pb)
	---@type StructDreamTripEventInfo
	local serverData = StructDreamTripEventInfo:New()
	serverData:CreateByPb(pb)
	return serverData
end

function StructDreamTripInfo:UpdateGridEventInfo(pb)
	local eventInfo = self:CreateDreamTripEventInfo(pb)
	local gridInfo = self:GetGridInfoByIndex(eventInfo.index)
	if not gridInfo then return end
	gridInfo:UpdateEventInfo(eventInfo)
end

---@return StructDreamTripGrid
function StructDreamTripInfo:GetGridInfoByIndex(index)
	return self.gridInfos[index]
end

function StructDreamTripInfo:SetIndex(index)
	self.index = index
end

function StructDreamTripInfo:SetDiceCount(diceCount)
	self.diceCount = diceCount
end

function StructDreamTripInfo:UpdateSuccessIndex()
	self.successIndex = {}
	self.successIndexKey = {}

	---@param v StructDreamTripGrid
	for k,v in pairs(self.gridInfos) do
		---@param eventInfo StructDreamTripEventInfo
		for key,eventInfo in pairs(v.eventMap) do
			if eventInfo.state == StructDreamTripGrid.FINISH then
				table.insert(self.successIndex,key)
				self.successIndexKey[key] = eventInfo
			end
		end
	end
end

function StructDreamTripInfo:CheckIsMapUpLevelState()
	local isUp = self.lastMapLvl > 0
	if isUp then
		self:ResetLastMapLvl()
	end
	return isUp
end

function StructDreamTripInfo:ResetLastMapLvl()
	self.lastMapLvl = 0
end

--- 终点事件是否完成
function StructDreamTripInfo:CheckIsEndPointFinish()
	local themeCfg = gModelFastDreamTrip:GetMapRefByMapId(self.mapId)
	if not themeCfg then return false end
	local endPlatform = themeCfg.endPlatform
	if not endPlatform or endPlatform < 1 then return false end
	---@type StructDreamTripGrid
	local endGrids = self.gridInfos[endPlatform]
	if not endGrids then return false end
	return endGrids:CheckGridIsFinish()
end

function StructDreamTripInfo:GetServerData()
	return {}
end

return StructDreamTripInfo